function getLoopedProgress(tm, st, dur, mode){
  var locT = tm - st;
  function cl(v){return clamp(v,0,1);} // shorthand

  if(mode==='none'){
    return cl(locT/dur);
  } else if(mode==='loop'){
    if(dur<=0) return 0;
    var mv = locT%dur; if(mv<0) mv+=dur;
    return cl(mv/dur);
  } else if(mode==='pingpong'){
    if(dur<=0) return 0;
    var cycle=2*dur;
    var mv2= locT%cycle; if(mv2<0) mv2+=cycle;
    if(mv2<=dur){
      return cl(mv2/dur);
    } else {
      return cl(1 - ((mv2-dur)/dur));
    }
  }
  return 0;
}

